/**
 * Render text to a pixel array (centered, clipped to display width).
 */
export function textToPixels(
  text: string,
  width: number,
  height: number,
  fgColor: HexColor = '#ff6600',
  bgColor: HexColor = '#111'
): PixelArray {
  const pixels: PixelArray = [];
  const charWidth = 6;
  const charHeight = 7;
  const startY = Math.floor((height - charHeight) / 2);

  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      pixels.push(bgColor);
    }
  }

  const textWidth = text.length * charWidth - 1;
  const startX = Math.max(1, Math.floor((width - textWidth) / 2));

  let xOffset = startX;
  for (const char of text) {
    const charData = pixelFont[char] || pixelFont[' '];
    for (let col = 0; col < 5; col++) {
      for (let row = 0; row < 7; row++) {
        const pixelOn = (charData[col] >> row) & 1;
        const px = xOffset + col;
        const py = startY + row;
        if (px >= 0 && px < width && py < height && py >= 0) {
          pixels[py * width + px] = pixelOn ? fgColor : bgColor;
        }
      }
    }
    xOffset += charWidth;
  }
  return pixels;
}

/**
 * Render text to an extended pixel array for scrolling.
 * Width is: displayWidth + textWidth + displayWidth (for seamless wrap).
 */
export function textToScrollPixels(
  text: string,
  displayWidth: number,
  height: number,
  fgColor: HexColor = '#ff6600',
  bgColor: HexColor = '#111'
): ScrollPixelsResult {
  const charWidth = 6;
  const charHeight = 7;
  const startY = Math.floor((height - charHeight) / 2);
  const textPixelWidth = text.length * charWidth;
  const extendedWidth = displayWidth + textPixelWidth + displayWidth;

  const pixels: PixelArray = [];
  for (let y = 0; y < height; y++) {
    for (let x = 0; x < extendedWidth; x++) {
      pixels.push(bgColor);
    }
  }

  let xOffset = displayWidth;
  for (const char of text) {
    const charData = pixelFont[char] || pixelFont[' '];
    for (let col = 0; col < 5; col++) {
      for (let row = 0; row < 7; row++) {
        const pixelOn = (charData[col] >> row) & 1;
        const px = xOffset + col;
        const py = startY + row;
        if (px >= 0 && px < extendedWidth && py < height && py >= 0) {
          pixels[py * extendedWidth + px] = pixelOn ? fgColor : bgColor;
        }
      }
    }
    xOffset += charWidth;
  }

  return { pixels, width: extendedWidth };
}
